/** Full markdown body for a doc. */
export function getDocBody(slug: string): string | undefined {
  return docBodies[slug]
}

/** Short summary for tooltips (from frontmatter). */
export function getDocSummary(slug: string): string | undefined {
  return userDocsManifest[slug]?.summary
}

/** Section content (markdown) for a doc; for modal or deep link. */
export function getDocSectionContent(
  slug: string,
  sectionId: string
): string | undefined {
  const list = docSections[slug]
  if (!list) return undefined
  const s = list.find(x => x.id === sectionId)
  return s?.content
}

/** Ordered list of slugs for TOC. */
export const userDocSlugs: string[] = ['concepts', 'getting-started', 'vision']
